head.script:
//==================================================================================================================
// id       : op_302_01_28b
// 이름     : 컨테이너반출신고
// 경로     : 물류/작업실적/EDI/세관/컨테이너반출신고
// 작 성 자 : 최지수
// 작 업 일 : 2026-04-03
//==================================================================================================================
//현재일자
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");

//-------------------------------------------------------------------------
// 공통: 체크된 행의 반출일시 14자리 패딩
//-------------------------------------------------------------------------
scwin.f_padCrryinoutDtm = function () {
    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1) {
            var dtm = ds_cntrOutDeclarInfo.getCellData(i, "crryinoutDtm");
            if (dtm.length < 14) {
                dtm = dtm + "00000000000000".substring(0, 14 - dtm.length);
                ds_cntrOutDeclarInfo.setCellData(i, "crryinoutDtm", dtm);
            }
        }
    }
};


//-------------------------------------------------------------------------
// 공통: 체크된 행의 반출일시/반출유형 필수값 검증
//-------------------------------------------------------------------------
scwin.f_validateCheckedRows = function () {
    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1) {
            if (ds_cntrOutDeclarInfo.getCellData(i, "crryinoutDtm") == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["반출일시"]);
                return false;
            }
            if (ds_cntrOutDeclarInfo.getCellData(i, "crryinoutPatternCd") == "") {
                $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["반출유형"]);
                return false;
            }
            if (ds_cntrOutDeclarInfo.getCellData(i, "crryinoutDtm").length < 14) {
                $c.gus.cfAlertMsg("반출일시는 년/월/일/시/분/초 까지 입력하셔야 합니다.");
                return false;
            }
            if (!scwin.f_isValidDateTime(ds_cntrOutDeclarInfo.getCellData(i, "crryinoutDtm"))) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["반출일시"]);
                return false;
            }
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// 공통: 작업장 유효성 검증
//-------------------------------------------------------------------------
scwin.f_isValidWrkPl = function () {
    for (var i = 0; i < ds_wrkPlCd.getRowCount(); i++) {
        if (ds_wrkPlCd.getCellData(i, "cd") == dma_condition.get("wrkPlCd")) {
            return true;
        }
    }
    return false;
};

scwin.onpageload = function () {
    gr_cntrOutDeclarInfo.setColumnReadOnly("termExtdBasisNo", false);
    const codeOptions = [
        { grpCd: "OP134", compID: "gr_cntrOutDeclarInfo:crryinoutPatternCd", opt: { "range": "1" } }
    ];

    $c.data.setCommonCode(codeOptions);

    ed_msn.setValue("");
    ed_hsn.setValue("");

    dma_condition.set("crryinoutClsCd", "O");

    $c.gus.cfDisableBtn([btn_Save, btn_Trans, btn_Delete]);

    dma_wrkPlCd.set("grpCd", "SD151");
    dma_wrkPlCd.set("cd", "");
    dma_wrkPlCd.set("cdNm", "");

    $c.sbm.execute(sbm_wrkPlCd);
};

scwin.onUdcCompleted = function () {
    ed_crryinoutDtmFrom.setValue(scwin.strToDate);
    ed_crryinoutDtmTo.setValue(scwin.strToDate);
    $c.gus.cfDisableBtn([btn_Save, btn_Trans, btn_Delete, btn_Add, btn_Cancel]);
    ed_wrkPlCd.focus();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    //검색조건 필수 입력 체크
    if (!await $c.gus.cfValidate([tb_searchCondition])) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_crryinoutDtmFrom.getValue(), ed_crryinoutDtmTo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_crryinoutDtmFrom.focus();
        return;
    }

    console.log("declar_chk.getValue():", declar_chk.getValue(), typeof declar_chk.getValue());
    if (declar_chk.getValue() == 1) {
        dma_condition.set("declarTrgtYn", "1");
    } else {
        dma_condition.set("declarTrgtYn", "0");
    }
    console.log("dma_condition declarTrgtYn:", dma_condition.get("declarTrgtYn"));
    console.log("dma_condition 전체:", JSON.stringify(dma_condition.getJSON()));

    $c.sbm.execute(sbm_Retrieve);

};

//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_searchCondition, [acb_cargoCls, acb_dealingYn, ed_crryinoutDtmFrom, ed_crryinoutDtmTo]);
    ed_crryinoutDtmFrom.setValue(scwin.strToDate);
    ed_crryinoutDtmTo.setValue(scwin.strToDate);
    acb_cargoCls.setSelectedIndex(0);
    acb_dealingYn.setSelectedIndex(0);
};


//-------------------------------------------------------------------------
// 전송
//-------------------------------------------------------------------------
scwin.f_Trans = async function () {

    var count = 0;

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1 && ds_cntrOutDeclarInfo.getCellData(i, "sndClsCd") == "4") {
            $c.gus.cfAlertMsg("전송구분이 전송제외인 경우에는 전송을 하실수가 없습니다.");
            ds_cntrOutDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1
            && (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "전송대기" ||
                ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "전송완료")) {
            $c.gus.cfAlertMsg("전송중에는 재전송을 하실수가 없습니다.");
            ds_cntrOutDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
    }

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1) {
            ds_cntrOutDeclarInfo.setCellData(i, "wrkPlCd", ed_wrkPlCd.getValue());
            count++;
        }
    }

    scwin.f_padCrryinoutDtm();

    if (!scwin.f_validateCheckedRows()) {
        return false;
    }

    if (!scwin.f_isValidWrkPl()) {
        $c.gus.cfAlertMsg(ed_wrkPlCd.getValue() + "작업장은 자료 전송이 불가능한 작업장입니다.");
        return false;
    }

    if (count == 0) {
        $c.gus.cfAlertMsg("전송할 컨테이너번호를 선택해 주세요.");
        return false;
    }

    if (await $c.win.confirm("전송하시겠습니까?")) {
        $c.sbm.execute(sbm_trans);
    }
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    var count = 0;

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1 && (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "전송완료"
            || ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == ""
            || ds_cntrOutDeclarInfo.getCellData(i, "sndClsCd") == "4")) {
            $c.gus.cfAlertMsg("전송구분이 전송완료/전송제외인 경우에는 저장을 하실수가 없습니다.");
            ds_cntrOutDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
    }

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1) {
            count++;
        }
    }

    scwin.f_padCrryinoutDtm();

    if (ds_cntrOutDeclarInfo.getModifiedIndex().length === 0) {
        $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    if (!scwin.f_validateCheckedRows()) {
        return false;
    }

    if (!scwin.f_isValidWrkPl()) {
        $c.gus.cfAlertMsg(ed_wrkPlCd.getValue() + "작업장은 컨테이너 반출신고를 할 수 없는 작업장입니다.");
        return false;
    }

    dma_condition.set("delYn", "0");

    if (declar_chk.getValue() == 1) {
        for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
            if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1) {
               // ds_cntrOutDeclarInfo.setCellData(i, "rowStatus", "C");
                ds_cntrOutDeclarInfo.modifyRowStatus(i, "C");
            }
        }
    }

    if (count == 0) {
        $c.gus.cfAlertMsg("저장할 컨테이너번호를 선택해 주세요.");
        return false;
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        $c.sbm.execute(sbm_save);
    }
};


//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    var count = 0;

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1) {
            count++;
        }
    }

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1
            && ds_cntrOutDeclarInfo.getCellData(i, "sndClsCd") != "3"
            && ds_cntrOutDeclarInfo.getCellData(i, "sndClsCd") != "4") {
            $c.gus.cfAlertMsg("삭제는 전송구분이 미전송/전송제외인 경우에만 가능합니다.");
            ds_cntrOutDeclarInfo.setCellData(i, "chk", 0);
            return false;
        }
    }

    if (!scwin.f_isValidWrkPl()) {
        $c.gus.cfAlertMsg(ed_wrkPlCd.getValue() + "작업장은 자료 삭제가 불가능한 작업장입니다.");
        return false;
    }

    if (count == 0) {
        $c.gus.cfAlertMsg("삭제할 컨테이너번호를 선택해 주세요.");
        return false;
    }

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == 1) {
            dma_condition.set("delYn", 1);
            ds_cntrOutDeclarInfo.modifyRowStatus(i, "D");
        }
    }

    if (await $c.win.confirm("삭제하시겠습니까?")) {
        $c.sbm.execute(sbm_delete);
    }
};

//-------------------------------------------------------------------------
// 반출근거번호 팝업창 호출
//--------------------------------------------------------------------
scwin.f_BasisNoPopup = function (row) {
    var v_mrn = ed_mrn.getValue();
    var v_msn = ed_msn.getValue();
    var v_hsn = ed_hsn.getValue();

    if ($c.gus.cfIsNull(v_hsn)) v_hsn = "0";

    let data = {
        param1: 0,
        param2: ed_wrkPlCd.getValue(),
        param3: ed_wrkPlNm.getValue(),
        param4: ds_cntrOutDeclarInfo.getCellData(row, "mrn"),
        param5: ds_cntrOutDeclarInfo.getCellData(row, "msn"),
        param6: ds_cntrOutDeclarInfo.getCellData(row, "hsn"),
        callbackFn: scwin.f_BasisNoPopup_callback
    };

    //팝업에서 리턴 시 사용할 행/검색조건 저장
    scwin._basisNoPopupRow = row;
    scwin._basisNoPopupMrn = v_mrn;
    scwin._basisNoPopupMsn = v_msn;
    scwin._basisNoPopupHsn = v_hsn;

    let opts = {
        id: "smpPop",
        popupName: "반출승인내역조회",
        modal: true,
        type: "browserPopup",
        width: 1200,
        height: 600,
        title: "반출승인내역조회"
    };

    $c.win.openPopup("/ui/ds/op/wrkrslts/yardwrkrslts/op_302_01_28p.xml", opts, data);
};

//반출근거번호 팝업 콜백
scwin.f_BasisNoPopup_callback = function (rtnValues) {
    if (rtnValues == null) return;

    var row = scwin._basisNoPopupRow;
    var v_mrn = scwin._basisNoPopupMrn;
    var v_msn = scwin._basisNoPopupMsn;
    var v_hsn = scwin._basisNoPopupHsn;

    ds_cntrOutDeclarInfo.setCellData(row, "crryinoutBasisNo", rtnValues[0]); // 반출승인번호

    //같은 MRN/MSN/HSN 행에도 반출근거번호 세팅
    for (var i = row + 1; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "mrn") == v_mrn
            && ds_cntrOutDeclarInfo.getCellData(i, "msn") == v_msn
            && ds_cntrOutDeclarInfo.getCellData(i, "hsn") == v_hsn) {
            ds_cntrOutDeclarInfo.setCellData(i, "crryinoutBasisNo", rtnValues[0]);
        }
    }
};

//-------------------------------------------------------------------------
// 오류 상세내역 조회 팝업
//-------------------------------------------------------------------------
scwin.f_errorPopUp = function (row) {
    //컨테이너 반입 오류시에도 오류상세내역 확인가능하게 수정
    var docCd = "";

    if (ds_cntrOutDeclarInfo.getCellData(row, 'crryinoutPatternCd') == '59') {
        docCd = "356";
    } else {
        docCd = "5LB";
    }

    var declarNo = ds_cntrOutDeclarInfo.getCellData(ds_cntrOutDeclarInfo.getRowPosition(), "crryinoutDeclarNo");
    var deg = 0;

    let data = {
        deg: deg,
        docCd: docCd,
        declarNo: declarNo
    };

    let opts = {
        id: "smpPop",
        popupName: "",
        modal: false,
        type: "browserPopup",
        width: 860,
        height: 580,
        title: ""
    };

    $c.win.openPopup("/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", opts, data);

};


//-------------------------------------------------------------------------
//  전송구분에 따른 Total 
//-------------------------------------------------------------------------
scwin.f_sndClsTotal = function () {
    var v_send = 0;//전송 
    var v_unSend = 0;//미전송
    var v_acpt = 0;//접수 
    var v_error = 0;//오류 
    var v_transComplete = 0; //전송완료
    var v_forceAcpt = 0; //강제접수

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "전송")
            v_send++;

        else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "미전송")
            v_unSend++;

        else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "접수")
            v_acpt++;

        else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "오류")
            v_error++;

        else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "전송완료")
            v_transComplete++;

        else if (ds_cntrOutDeclarInfo.getCellData(i, "sndClsNm") == "강제접수")
            v_forceAcpt++;
    }

    send.setValue(v_send);
    unSend.setValue(v_unSend);
    acpt.setValue(v_acpt);
    error.setValue(v_error);
    transComplete.setValue(v_transComplete);
    forceAcpt.setValue(v_forceAcpt);
};


//-------------------------------------------------------------------------
// 강제접수
//-------------------------------------------------------------------------
scwin.f_forcedReceipt = async function () {
    if (await $c.win.confirm("강제접수처리 하시겠습니까?")) {
        $c.sbm.execute(sbm_forcedReceipt);
    }
};


//////////////////////////////////////// S U B M I S S I O N    E V E N T //////////////////////////////////
scwin.sbm_Retrieve_submitdone = function (e) {
    console.log("sbm_Retrieve 응답:", JSON.stringify(e.responseJSON.resultDataSet));
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        console.error("sbm_Retrieve 에러:", e.responseJSON.resultDataSet[0].Message);
        $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[0].Message);
        return;
    }

    grp_totalArea.setStyle("visibility", "visible");

    if (ds_cntrOutDeclarInfo.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    }
    totalRows.setValue(ds_cntrOutDeclarInfo.getRowCount());

    scwin.f_sndClsTotal();  //전송 구분 별 Total 

    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        //adminNo, decalreNo 값이 있으면 반출유형/반출근거번호 매핑
        if (ds_cntrOutDeclarInfo.getCellData(i, "adminNo") != "") {
            ds_cntrOutDeclarInfo.setCellData(i, "crryinoutPatternCd", "50");
            ds_cntrOutDeclarInfo.setCellData(i, "crryinoutBasisNo", ds_cntrOutDeclarInfo.getCellData(i, "adminNo"));
        } else if (ds_cntrOutDeclarInfo.getCellData(i, "decalreNo") != "") {
            ds_cntrOutDeclarInfo.setCellData(i, "crryinoutPatternCd", "50");
            ds_cntrOutDeclarInfo.setCellData(i, "crryinoutBasisNo", ds_cntrOutDeclarInfo.getCellData(i, "decalreNo"));
        }

        //경과일 폰트색 변경
        if (ds_cntrOutDeclarInfo.getCellData(i, "arrowDt") >= 15) {
            gr_cntrOutDeclarInfo.setCellStyle(i, "arrowDt", "color", "red");
        }

        //반출근거번호 폰트색 변경 (crryinoutBasisNoPre 값 기준으로 crryinoutBasisNo 컬럼에 적용)
        if (ds_cntrOutDeclarInfo.getCellData(i, "crryinoutBasisNoPre") == "") {
            gr_cntrOutDeclarInfo.setCellStyle(i, "crryinoutBasisNo", "color", "black");
        } else {
            gr_cntrOutDeclarInfo.setCellStyle(i, "crryinoutBasisNo", "color", "red");
        }
    }

    if (declar_chk.getValue() == 1) {
        $c.gus.cfDisableBtn([btn_Trans, btn_Delete]);
        $c.gus.cfEnableObjects([btn_Add, btn_Cancel]);
    } else {
        $c.gus.cfEnableObjects([btn_Save, btn_Trans, btn_Delete]);
        $c.gus.cfDisableBtn([btn_Add, btn_Cancel]);
    }


    //전송구분이 오류이면 반출신고번호 폰트 변경
    for (var j = 0; j < ds_cntrOutDeclarInfo.getRowCount(); j++) {
        if (ds_cntrOutDeclarInfo.getCellData(j, "sndClsNm") == "오류") {
            gr_cntrOutDeclarInfo.setCellStyle(j, "crryinoutDeclarNo", "textDecoration", "underline");
            gr_cntrOutDeclarInfo.setCellStyle(j, "crryinoutDeclarNo", "cursor", "pointer");
        }
    }

    ds_cntrOutDeclarInfo.modifyAllStatus("R");

    // 첫 행 포커스
    if (ds_cntrOutDeclarInfo.getRowCount() > 0) {
        ds_cntrOutDeclarInfo.setRowPosition(0);
        gr_cntrOutDeclarInfo.setFocusedCell(0, 0, true);
    }
};

scwin.sbm_trans_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        $c.gus.cfShowError(sbm_trans);
        return;
    }

    $c.gus.cfAlertMsg("성공적으로 전송하였습니다.");
    dma_condition.set("delYn", 0);
    scwin.f_Retrieve();
};

scwin.sbm_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
      //  $c.gus.cfShowError(sbm_save);
        scwin.addRowYn = "F";
        return;
    }

    $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    $c.gus.cfEnableObjects([btn_Trans]);
    scwin.addRowYn = "F";
    scwin.f_Retrieve();
};


scwin.sbm_delete_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        $c.gus.cfShowError(sbm_delete);
        return;
    }

    $c.gus.cfAlertMsg(MSG_CM_INF_004);	// 성공적으로 삭제하였습니다
    dma_condition.set("delYn", 0);
    scwin.f_Retrieve();
};

scwin.sbm_wrkPlCd_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        $c.gus.cfShowError(sbm_wrkPlCd);
        return;
    }

};

scwin.sbm_forcedReceipt_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        $c.gus.cfShowError(sbm_forcedReceipt);
        return;
    }
    $c.gus.cfAlertMsg(MSG_CM_INF_003);	// 성공적으로 수정하였습니다
    scwin.f_Retrieve();
};

//////////////////////////////////////// C O M P O N E N T   E V E N T //////////////////////////////////

//작업장 UDC
scwin.udc_comCodeWrk_onclickEvent = function (e) {
    udc_comCodeWrkPl.cfCommonPopUp(
        scwin.udc_comCodeWrkPl_callBackFunc,
        ed_wrkPlCd.getValue(),
