//-------------------------------------------------------------------------
// function name : f_inputGridAddrow
// function desc : 행추가
//-------------------------------------------------------------------------
scwin.f_inputGridAddrow = function () {
    scwin.addRowYn = "T";

    var chkFlag = "T";
    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "crryinoutDeclarNo") != "") {
            chkFlag = "F";
            break;
        }
    }
    if (chkFlag == "F") {
        $c.win.alert("다시 조회하여 주십시오.");
        return;
    }

    if (ds_cntrOutDeclarInfo.getRowCount() == 0) {
        return;
    }

    var curRow = -1;
    for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
        if (ds_cntrOutDeclarInfo.getCellData(i, "chk") == "1") {
            curRow = i;
            break;
        }
    }

    if (curRow < 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["컨테이너"]);
        return;
    }

    var newRow = curRow + 1;
    ds_cntrOutDeclarInfo.insertRow(newRow);
    ds_cntrOutDeclarInfo.setCellData(newRow, "chk", "1");
    ds_cntrOutDeclarInfo.setCellData(newRow, "cntrNo", ds_cntrOutDeclarInfo.getCellData(curRow, "cntrNo"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "crryinoutDeclarNo", ds_cntrOutDeclarInfo.getCellData(curRow, "crryinoutDeclarNo"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "mrn", ds_cntrOutDeclarInfo.getCellData(curRow, "mrn"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "msn", ds_cntrOutDeclarInfo.getCellData(curRow, "msn"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "hsn", ds_cntrOutDeclarInfo.getCellData(curRow, "hsn"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "crryinoutDtm", ds_cntrOutDeclarInfo.getCellData(curRow, "crryinoutDtm"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "crryinoutPatternCd", ds_cntrOutDeclarInfo.getCellData(curRow, "crryinoutPatternCd"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "crryoutTermExtdClsNm", ds_cntrOutDeclarInfo.getCellData(curRow, "crryoutTermExtdClsNm"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "termExtdBasisNo", ds_cntrOutDeclarInfo.getCellData(curRow, "termExtdBasisNo"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "crryinoutBasisNo", ds_cntrOutDeclarInfo.getCellData(curRow, "crryinoutBasisNo"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "sndClsNm", ds_cntrOutDeclarInfo.getCellData(curRow, "sndClsNm"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "declarNm", ds_cntrOutDeclarInfo.getCellData(curRow, "declarNm"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "declarCstmNm", ds_cntrOutDeclarInfo.getCellData(curRow, "declarCstmNm"));
    ds_cntrOutDeclarInfo.setCellData(newRow, "addRowYn", scwin.addRowYn);

    gr_cntrOutDeclarInfo.setFocusedCell(newRow, "cntrNo", true);
};

