//-------------------------------------------------------------------------
// function name : f_isValidDateTime
// function desc : YYYYMMDDHHmmss 형식 날짜 유효성 검증
//-------------------------------------------------------------------------
scwin.f_isValidDateTime = function (dtm) {
    if (!dtm || dtm.length != 14) return false;
    var y = parseInt(dtm.substring(0, 4), 10);
    var m = parseInt(dtm.substring(4, 6), 10);
    var d = parseInt(dtm.substring(6, 8), 10);
    var h = parseInt(dtm.substring(8, 10), 10);
    var mi = parseInt(dtm.substring(10, 12), 10);
    var s = parseInt(dtm.substring(12, 14), 10);
    if (m < 1 || m > 12) return false;
    if (d < 1 || d > 31) return false;
    if (h < 0 || h > 23) return false;
    if (mi < 0 || mi > 59) return false;
    if (s < 0 || s > 59) return false;
    var dt = new Date(y, m - 1, d);
    if (dt.getFullYear() != y || dt.getMonth() != m - 1 || dt.getDate() != d) return false;
    return true;
};

scwin._fromPopup = false;

scwin.gr_cntrOutDeclarInfo_onafteredit = function (rowIndex, columnIndex, value) {
    var v_mrn = ed_mrn.getValue();
    var v_msn = ed_msn.getValue();
    var v_hsn = ed_hsn.getValue();
    if ($c.gus.cfIsNull(v_hsn)) v_hsn = "0";

    let colid = gr_cntrOutDeclarInfo.getColumnID(columnIndex);

    //반출근거번호: 팝업에서 돌아온 경우 onafteredit 무시
    if (colid == "crryinoutBasisNo" && scwin._fromPopup) {
        scwin._fromPopup = false;
        return;
    }

    //반출근거번호: 값 입력 후 엔터 시 팝업 호출 (ASIS OnExit 동작)
    if (colid == "crryinoutBasisNo") {
        if (value != "") {
            scwin.f_BasisNoPopup(rowIndex);
        } else {
            ds_cntrOutDeclarInfo.setCellData(rowIndex, "crryinoutBasisNo", "");
        }
        return;
    }

    if (colid == "crryinoutPatternCd") {
        for (var i = rowIndex + 1; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {

            if (ds_cntrOutDeclarInfo.getCellData(i, "mrn") == v_mrn
                && ds_cntrOutDeclarInfo.getCellData(i, "msn") == v_msn
                && ds_cntrOutDeclarInfo.getCellData(i, "hsn") == v_hsn) {
                ds_cntrOutDeclarInfo.setCellData(i, "crryinoutPatternCd", ds_cntrOutDeclarInfo.getCellData(rowIndex, "crryinoutPatternCd"));
            }
        }
    }

};


/* 반출일시 포맷 — 분까지만 표시 (ASIS mask XXXX/XX/XX XX:XX 동일) */
scwin.crryinoutDtmFormatter = function (data) {
    if (!data || data == "" || data == "0") return "";
    var val = String(data);
    if (val.indexOf("/") >= 0 && val.length > 16) {
        return val.substring(0, 16);
    }
    if (val.length >= 12) {
        return val.substring(0, 4) + "/" + val.substring(4, 6) + "/" + val.substring(6, 8) + " " + val.substring(8, 10) + ":" + val.substring(10, 12);
    }
    return val;
};

scwin.displayFm = function (data) {
    // 1. decode된 값
    var val = $c.gus.decode(data, 0, "", data);

    // 2. 숫자 여부 확인 후 콤마 적용
    if (!isNaN(val) && val !== null && val !== "") {
        val = Number(val).toLocaleString();
    }

    return val;
};


//반출근거번호 팝업 (그리드 돋보기 클릭)
scwin.gr_cntrOutDeclarInfo_ontextimageclick = function (rowIndex, columnIndex) {
    var colId = gr_cntrOutDeclarInfo.getColumnID(columnIndex);
    if (colId == "crryinoutBasisNo") {
        scwin._fromPopup = true;
        scwin.f_BasisNoPopup(rowIndex);
    }
};


scwin.gr_cntrOutDeclarInfo_oncelldblclick = async function (rowIndex, columnIndex, columnId) {
    let colid = columnId;

    if (colid == "crryinoutDeclarNo") {
        if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") == "오류") {
            scwin.f_errorPopUp(rowIndex);
        }
    }

    if (colid == "chk") {
        // 미반영된 반출 승인이 있는데 전송 하시겠습니까?  
        if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "crryinoutBasisNoPre") != "") {
            if (!await $c.win.confirm("미반영된 반출 승인이 있습니다. 계속 진행 하시겠습니까?")) {
                ds_cntrOutDeclarInfo.setCellData(rowIndex, "chk", 0);
                return false;
            }
        }

        if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsCd") != "3"
            && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") != "오류"
            && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") != "전송완료"
            && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsNm") != ""
            && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsCd") != "4"
            && ds_cntrOutDeclarInfo.getCellData(rowIndex, "sndClsCd") != "5") {
            $c.gus.cfAlertMsg("전송구분이 전송완료/미전송/전송제외/오류/필수항목오류인 경우에만 선택하실수 있습니다.");
            ds_cntrOutDeclarInfo.setCellData(rowIndex, "chk", 0);
            return false;
        }

        //같은 컨테이너번호 행 연동 체크
        for (var i = 0; i < ds_cntrOutDeclarInfo.getRowCount(); i++) {
            if (ds_cntrOutDeclarInfo.getCellData(rowIndex, "chk") == 1 &&
                ds_cntrOutDeclarInfo.getCellData(rowIndex, "cntrNo") == ds_cntrOutDeclarInfo.getCellData(i, "cntrNo")) {
                ds_cntrOutDeclarInfo.setCellData(i, "chk", 1);
            }
        }
    }
};

